VALUES
  ('heelevel3-6e2f88c7-moex-00052', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於訴願之期限，下列敘述何者正確？', '["訴願之提起，應於原行政處分機關或受理訴願機關收受訴願書當日起算30日內", "訴願之決定，自收受訴願書之次日起，原則上應於2個月內為之", "訴願決定書應附記，如不服決定，得於決定書送達之次日起1個月內向行政法院提起行政訴訟", "訴願決定書之正本，應於決定後15日內送達訴願人、參加人及原行政處分機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00053', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政處分之效力，下列敘述何者錯誤？', '["已無法再循通常救濟途徑予以變更或撤銷之行政處分，除別有規定外，即產生形式存續力", "行政處分須直到發生形式存續力後，方對相對人及原處分機關產生拘束力", "行政程序法第128條關於行政程序重新進行之規定，係行政處分形式存續力之例外", "違法行政處分於法定救濟期間經過後，原處分機關仍得依職權撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00054', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '下列何者屬於附負擔附款之行政處分？', '["在普通汽車駕駛執照中，附記不得操作大客車", "發給施工許可，但註記施工期間3個月", "主管機關許可舉辦演唱會，但將舉辦方所申請之4小時調整為3小時", "行政機關同意資助公務員出國進修，但進修結束後5年內不得離職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00055', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '於颱風來襲時，某山地原住民區公所依災害防救法之規定，強制某一危險地區之住戶立即撤離， 此一強制撤離行為的法律性質為何？', '["行政事實行為", "行政指導", "法規命令", "一般處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00056', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政事實行為之敘述，下列何者正確？', '["行政事實行為不發生法律效果，應類推適用確認行政處分無效之訴訟救濟之", "行政事實行為不具法律效果，但是亦為行政法律關係發生原因之一", "通知人民自行拆除違章建築屬於行政事實行為", "行政事實行為僅具事實效力，故無須遵守法律優位原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00057', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依現行法及司法實務見解，下列何者非屬行政契約？', '["義務人與法務部行政執行署締結之分期繳納罰款契約", "教育部與公費留學生締結之公費留學契約", "公立學校與教師間締結之聘約", "退除役軍職人員與臺灣銀行締結之優惠存款契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00058', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '下列何者非屬行政罰？', '["稅捐稽徵機關對於欠稅者為限制出境處分", "企業未依電信管理相關法令申請許可，私自架設、使用電臺設備，該企業遭主管機關罰鍰", "汽車駕駛人違反道路交通管理處罰條例，被裁處參加道路交通安全講習", "電視臺持續播放違反法律強制規定之節目，主管機關吊銷其執照"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00059', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依行政執行法規定，有關原處分機關或行政執行分署為行政執行之敘述，下列何者錯誤？', '["行政執行分署為執行公法上金錢給付義務事項，得將權限之一部分委託民間團體辦理", "行政執行由原處分機關執行時，以實施行政處分時之名義認定原處分機關", "上級機關本於法定職權所為之行政處分，交由下級機關執行者，以該下級機關為原處分機關", "原處分機關裁撤或改組者，以承受其業務之機關為執行機關 23550"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00060', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於人民依法申請閱覽卷宗之敘述，下列何者錯誤？', '["涉及國防、軍事、外交機密且依法規規定有保密必要之卷宗資料，不予提供", "人民申請檢視公文資料，行政機關應視具體個案，分別適用行政程序法、檔案法或政府資訊公 開法之相關規定", "涉及一般公務機密之行政決定前擬稿或準備文件，與公益無關之部分，依法仍應准許閱覽", "當事人於閱覽資料或卷宗時發現有錯誤，得檢具事實證明依法申請相關機關更正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00061', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '甲、乙、丙、丁、戊、己等6人共同提起訴願，依訴願法規定，下列敘述何者錯誤？', '["甲等6人因同一原因事實，受課稅處分，得共同提起訴願", "甲、乙為訴願選定代表人，則甲、乙均得單獨代表共同訴願人為訴願行為", "甲等6人經通知逾期未選定訴願代表人，受理訴願機關得依職權指定訴願代表人", "甲等6人共同提起訴願，得選定甲、乙、丙、丁為代表人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
